import { Button } from "@/components/ui/button";
import { Trash2Icon } from "lucide-react";
import Image from "next/image";
import React from "react";
// const OrderedItems = ({ id,description,imageUrl,price,productBarcode,productName,quantity,createdAt }: Product) =>

const OrderedItems = () => {
  return (
    <div className="m-2 p-2 border-2 border-[#fff]">
      <div
        className="w-full h-50 flex flex-row rounded-lg bg-[#fff]"
      >
        <div className="md:w-2/5 shrink-0">
          <Image
            src="/products/panda-pen.png"
            width={150}
            height={150}
            alt="image"
            className="object-contain h-full w-[150]"
          />
        </div>
        <div className="w-full flex flex-col ">
          <div className="py-5 px-0">
            <h3 className="md:text-lg text-[#5e5e5e] break-all">
              Office Warehouse Inc - Panda Pen"
            </h3>
            <span className="md:text-md font-bold text-[#216c58]">
              ₱40
            </span>
          </div>
          {/* <p className="text-sm pt-5 ml-5 mr-5">{products.description}</p> */}
          <div className="flex m-3 mt-auto">
            <div className="sm:space-x-3 md:space-x-5 space-x-5 flex flex-row items-center">
              <Button
                onClick={() => decrease(products.id)}
                variant="outline"
                size="icon"
                className="size-8 text-[#b94350] border-[#b94350] cursor-pointer hover:bg-[#b94350]"
              >
                <Trash2Icon className="" />
              </Button>
              <span className="text-sm font-bold text-gray-700 dark:text-white">
                1
              </span>
              <Button
                onClick={() => increase(products.id)}
                variant="outline"
                size="icon"
                className="size-8 text-[#276857] border-[#276857] cursor-pointer hover:bg-[#78d0b9]"
              >
                <PlusSquareIcon className="" />
              </Button>
            </div>
            <div className="flex ml-auto p-3 justify-end items-end break-all">
              <p className="text-sm text-[#5e5e5e]">
                Total:&nbsp;
                <span className="text-sm text-[#216c58] font-bold">
                  ₱{products.quantity * products.price}
                </span>
              </p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default OrderedItems;
